import {createPortal} from 'react-dom';
import {useEffect,useRef} from 'react';
interface Props{open:boolean;onClose:()=>void;title:string;children:React.ReactNode}
export function Modal({open,onClose,title,children}:Props){
  const ref=useRef<HTMLDivElement>(null);
  useEffect(()=>{
    if(!open)return;
    const onKey=(e:KeyboardEvent)=>{if(e.key==='Escape')onClose();};
    document.addEventListener('keydown',onKey);
    ref.current?.querySelector<HTMLElement>('[autofocus],button,input,a,select,textarea')?.focus();
    return ()=>document.removeEventListener('keydown',onKey);
  },[open,onClose]);
  if(!open)return null;
  return createPortal(
    <div role="dialog" aria-modal="true" aria-labelledby="modal-title" ref={ref} onClick={(e)=>{if(e.target===e.currentTarget)onClose();}} style={{position:'fixed',inset:0}}>
      <div role="document" onClick={(e)=>e.stopPropagation()}>
        <h2 id="modal-title">{title}</h2>
        {children}
        <button onClick={onClose}>Close</button>
      </div>
    </div>,
    document.body
  );
}

