// src/csv/csv.ts
export function encodeCsv(rows:string[][]):string{
  return rows.map(r=>r.map(field=>{
    if(/[,"\n\r]/.test(field))return `"${field.replace(/"/g,'""')}"`;
    return field;
  }).join(',')).join('\n');
}
export function decodeCsv(s:string):string[][]{
  const rows:string[][]=[];
  let row:string[]=[];
  let field='';
  let inQuotes=false;
  for(let i=0;i<s.length;i++){
    const c=s[i];
    if(inQuotes){
      if(c==='"'){
        if(s[i+1]==='"'){field+='"';i++;}
        else inQuotes=false;
      }else field+=c;
    }else{
      if(c==='"')inQuotes=true;
      else if(c===','){row.push(field);field='';}
      else if(c==='\n'){row.push(field);rows.push(row);row=[];field='';}
      else if(c==='\r'){/* skip */}
      else field+=c;
    }
  }
  if(field!==''||row.length){row.push(field);rows.push(row);}
  return rows;
}

// src/csv/csv.property.test.ts
import {describe,it} from 'vitest';
import fc from 'fast-check';
import {encodeCsv,decodeCsv} from './csv';

const fieldArb=fc.string({maxLength:20});
const rowArb=fc.array(fieldArb,{minLength:1,maxLength:5});
const rowsArb=fc.array(rowArb,{minLength:1,maxLength:10}).filter(rows=>{
  const w=rows[0].length;
  return rows.every(r=>r.length===w); // CSV needs consistent width for round-trip
});

describe('CSV round-trip',()=>{
  it('decode(encode(rows)) === rows for arbitrary content',()=>{
    fc.assert(fc.property(rowsArb,(rows)=>{
      const csv=encodeCsv(rows);
      const parsed=decodeCsv(csv);
      if(parsed.length!==rows.length)return false;
      for(let i=0;i<rows.length;i++){
        if(parsed[i].length!==rows[i].length)return false;
        for(let j=0;j<rows[i].length;j++)if(parsed[i][j]!==rows[i][j])return false;
      }
      return true;
    }),{numRuns:500});
  });
  it('handles fields with embedded comma+quote+newline (REGRESSION GUARD)',()=>{
    const rows=[['a,"b"\nc','simple']];
    const csv=encodeCsv(rows);
    expect(decodeCsv(csv)).toEqual(rows);
  });
});

