import type {RequestHandler} from 'express';
import {z} from 'zod';
const Body=z.object({
  items:z.array(z.object({sku:z.string().min(1),qty:z.number().int().positive()})).min(1).max(50),
  notes:z.string().max(500).nullable().optional(),
