// src/auth/jwt.ts
import crypto from 'node:crypto';
import {Buffer} from 'node:buffer';

export class JwtError extends Error{}

function b64url(b:Buffer):string{return b.toString('base64url');}
function sign(parts:string,secret:string):string{return b64url(crypto.createHmac('sha256',secret).update(parts).digest());}

export function signJwt(payload:object,secret:string):string{
  const header=b64url(Buffer.from(JSON.stringify({alg:'HS256',typ:'JWT'})));
  const body=b64url(Buffer.from(JSON.stringify(payload)));
  const sig=sign(`${header}.${body}`,secret);
  return `${header}.${body}.${sig}`;
}

export function verifyJwt<T=unknown>(token:string,secret:string):T{
  const parts=token.split('.');
  if(parts.length!==3)throw new JwtError('malformed');
  const [h,b,s]=parts;
  const expected=sign(`${h}.${b}`,secret);
  if(s.length!==expected.length||!crypto.timingSafeEqual(Buffer.from(s),Buffer.from(expected)))throw new JwtError('signature');
  return JSON.parse(Buffer.from(b,'base64url').toString('utf8'));
}

// src/auth/jwt.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {signJwt,verifyJwt,JwtError} from './jwt';

const payloadArb=fc.dictionary(fc.string({minLength:1,maxLength:8}).filter(s=>/^[a-z]+$/.test(s)),fc.oneof(fc.string(),fc.integer(),fc.boolean()));
const secret='test-secret-shared';

describe('jwt properties',()=>{
  it('verify(sign(p)) === p',()=>{
    fc.assert(fc.property(payloadArb,(p)=>{
      const token=signJwt(p,secret);
      const decoded=verifyJwt<typeof p>(token,secret);
      return JSON.stringify(decoded)===JSON.stringify(p);
    }),{numRuns:500});
  });
  it('tampering ANY part fails verification',()=>{
    fc.assert(fc.property(payloadArb,fc.integer({min:0}),(p,offset)=>{
      const token=signJwt(p,secret);
      if(offset>=token.length)return true;
      const tampered=token.slice(0,offset)+(token[offset]==='a'?'b':'a')+token.slice(offset+1);
      try{verifyJwt(tampered,secret);return false;}
      catch(e){return e instanceof JwtError;}
    }),{numRuns:300});
  });
  it('wrong secret fails',()=>{
    fc.assert(fc.property(payloadArb,(p)=>{
      const token=signJwt(p,secret);
      try{verifyJwt(token,'wrong-secret');return false;}
      catch{return true;}
    }),{numRuns:200});
  });
  it('malformed token throws JwtError',()=>{
    expect(()=>verifyJwt('not.valid',secret)).toThrow(JwtError);
    expect(()=>verifyJwt('',secret)).toThrow(JwtError);
  });
});

