export interface User{tier:'free'|'pro'|'enterprise';signupAt:number}
export interface Item{categoryId:string;priceCents:number}
export function hasDiscount(user:User,item:Item,now:number):boolean{
  const isPro=user.tier==='pro'||user.tier==='enterprise';
  const isNewUser=now-user.signupAt<30*24*60*60*1000;
  const isExpensive=item.priceCents>=5000;
  return (isPro&&isExpensive)||(isNewUser&&!isExpensive);
}

