// tests/setup/intersection-observer.ts
class MockIO{
  static instances:MockIO[]=[];
  callbacks:Map<Element,(e:IntersectionObserverEntry[])=>void>=new Map();
  constructor(public callback:IntersectionObserverCallback,public options?:IntersectionObserverInit){MockIO.instances.push(this);}
  observe(el:Element){this.callbacks.set(el,(e)=>this.callback(e,this as unknown as IntersectionObserver));}
  unobserve(el:Element){this.callbacks.delete(el);}
  disconnect(){this.callbacks.clear();}
  takeRecords(){return [];}
  root=null;rootMargin='';thresholds=[];
  static triggerFor(el:Element,isIntersecting:boolean){
    for(const inst of MockIO.instances){
      const cb=inst.callbacks.get(el);
      if(cb)cb([{isIntersecting,target:el,intersectionRatio:isIntersecting?1:0,boundingClientRect:el.getBoundingClientRect(),intersectionRect:el.getBoundingClientRect(),rootBounds:null,time:Date.now()}]);
    }
  }
}
(globalThis as any).IntersectionObserver=MockIO;

// src/ui/LazyImage.tsx
import {useEffect,useRef,useState} from 'react';
export function LazyImage({src,alt}:{src:string;alt:string}){
  const ref=useRef<HTMLImageElement>(null);
  const [loaded,setLoaded]=useState(false);
  useEffect(()=>{
    if(!ref.current)return;
    const io=new IntersectionObserver(([e])=>{if(e.isIntersecting)setLoaded(true);},{threshold:0.1});
    io.observe(ref.current);
    return ()=>io.disconnect();
  },[]);
  return <img ref={ref} src={loaded?src:'data:image/gif;base64,R0lGODlhAQABAAAAACw='} alt={alt}/>;
}

