export default class FeatureSummaryReporter implements Reporter{
  private results=new Map<string,{pass:number;fail:number}>();
  onInit(_ctx:Vitest){}
  onTaskUpdate(packs:Array<[string,any]>){
    for(const [,task] of packs){
      if(task.type!=='test')continue;
      const feature=this.featureOf(task.file?.filepath??'');
      const entry=this.results.get(feature)??{pass:0,fail:0};
      if(task.result?.state==='pass')entry.pass++;
      else if(task.result?.state==='fail')entry.fail++;
      this.results.set(feature,entry);
    }
  }
  private featureOf(path:string):string{
    const m=path.match(/\/src\/([^\/]+)\//);
    return m?m[1]:'misc';
  }
  onFinished(){
    const summary=[...this.results.entries()].map(([k,v])=>`${k.padEnd(15)} ${v.pass} passed, ${v.fail} failed`).join('\n');
    console.log('\n=== Feature Summary ===\n'+summary);
    writeFileSync('feature-summary.txt',summary);
  }
}

