import type {RequestHandler} from 'express';
import {EventEmitter} from 'node:events';
export const events=new EventEmitter();

export const sseEndpoint:RequestHandler=(req,res)=>{
  res.setHeader('Content-Type','text/event-stream');
  res.setHeader('Cache-Control','no-cache');
  res.setHeader('Connection','keep-alive');
  res.flushHeaders();
  let id=0;
  const send=(payload:object)=>{id++;res.write(`id: ${id}\ndata: ${JSON.stringify(payload)}\n\n`);};
  const hb=setInterval(()=>res.write(':hb\n\n'),15000);
  const onEvent=(p:object)=>send(p);
  events.on('msg',onEvent);
  req.on('close',()=>{clearInterval(hb);events.off('msg',onEvent);});
};

