export type Role='guest'|'member'|'manager'|'admin';
export type Action='read'|'write'|'delete'|'admin_only';
const MATRIX:Record<Role,Set<Action>>={
  guest:new Set(['read']),
  member:new Set(['read','write']),
  manager:new Set(['read','write','delete']),
  admin:new Set(['read','write','delete','admin_only'])
};
export function can(role:Role,action:Action):boolean{return MATRIX[role].has(action);}
const ORDER:Role[]=['guest','member','manager','admin'];
export function elevates(a:Role,b:Role):boolean{return ORDER.indexOf(b)<=ORDER.indexOf(a);}

// src/auth/can.property.test.ts
