import {can,elevates,type Role,type Action} from './can';

const roleArb=fc.constantFrom<Role>('guest','member','manager','admin');
const actionArb=fc.constantFrom<Action>('read','write','delete','admin_only');

describe('can properties',()=>{
  it('role hierarchy is monotonic (elevates ⇒ can do anything lower can)',()=>{
    fc.assert(fc.property(roleArb,roleArb,actionArb,(higher,lower,action)=>{
      if(!elevates(higher,lower))return true;
      if(can(lower,action))return can(higher,action);
      return true;
    }),{numRuns:200});
  });
