import type {RequestHandler} from 'express';
import type {Pool} from 'pg';
export function saveDoc(db:Pool):RequestHandler{
  return async(req,res)=>{
    const {id,content,version}=req.body as {id:string;content:string;version:number};
    const r=await db.query<{version:number}>(
      'UPDATE docs SET content=$1, version=version+1, updated_at=NOW() WHERE id=$2 AND version=$3 RETURNING version',
      [content,id,version]
    );
    if(r.rowCount===0){
      const current=await db.query<{version:number}>('SELECT version FROM docs WHERE id=$1',[id]);
      return res.status(409).json({error:'conflict',currentVersion:current.rows[0]?.version});
    }
    res.json({version:r.rows[0].version});
  };
}

