import {useState,useTransition} from 'react';
interface Props{initialCount:number;onLike:()=>Promise<{count:number}>}
export function LikeButton({initialCount,onLike}:Props){
  const [count,setCount]=useState(initialCount);
  const [error,setError]=useState<string|null>(null);
  const [pending,startTransition]=useTransition();
  function click(){
    setError(null);
    setCount(c=>c+1); // optimistic
    startTransition(async()=>{
      try{
        const r=await onLike();
        setCount(r.count);
      }catch(e){
        setCount(c=>c-1); // rollback
        setError(e instanceof Error?e.message:'Failed');
      }
    });
  }
  return (
    <div>
      <button onClick={click} disabled={pending} aria-label="like">♡ <span data-testid="count">{count}</span></button>
      {error&&<span role="alert">{error}</span>}
    </div>
  );
}

