import type {RequestHandler} from 'express';
import type {Redis} from 'ioredis';
import crypto from 'node:crypto';

export function withIdempotency(redis:Redis,ttlSec=86400):RequestHandler{
  return async(req,res,next)=>{
    const key=req.header('idempotency-key');
    if(!key)return next();
    const bodyHash=crypto.createHash('sha256').update(JSON.stringify(req.body)).digest('hex');
    const cacheKey=`idemp:${key}`;
    const cached=await redis.get(cacheKey);
    if(cached){
      const {bodyHash:storedHash,response}=JSON.parse(cached);
      if(storedHash!==bodyHash)return res.status(422).json({error:'idempotency_mismatch'});
      return res.status(response.status).json(response.body);
    }
    // Intercept response to cache it
    const origJson=res.json.bind(res);
    res.json=function(body:unknown):any{
      const payload={bodyHash,response:{status:res.statusCode,body}};
      redis.set(cacheKey,JSON.stringify(payload),'EX',ttlSec).catch(()=>{});
      return origJson(body);
    };
    next();
  };
}

