afterAll(()=>redis.quit());

function app(){
  const a=express();a.use(express.json());a.use(withIdempotency(redis));
  let counter=0;
  a.post('/charge',(req,res)=>{counter++;res.status(201).json({id:`ch_${counter}`,amount:(req.body as any).amount});});
  return a;
}

beforeEach(async()=>{await redis.flushdb();});

describe('idempotency',()=>{
  it('same key + same body returns same response',async()=>{
    const key=nanoid();
    const a=app();
    const r1=await request(a).post('/charge').set('Idempotency-Key',key).send({amount:1000}).expect(201);
    const r2=await request(a).post('/charge').set('Idempotency-Key',key).send({amount:1000}).expect(201);
    expect(r2.body).toEqual(r1.body);
  });
  it('same key + different body returns 422',async()=>{
    const key=nanoid();
    const a=app();
    await request(a).post('/charge').set('Idempotency-Key',key).send({amount:1000}).expect(201);
