import crypto from 'node:crypto';
export function evaluateFlag(userId:string,flagKey:string,percentage:number):boolean{
  if(percentage<=0)return false;
  if(percentage>=100)return true;
  const h=crypto.createHash('md5').update(`${flagKey}:${userId}`).digest();
  const bucket=h.readUInt32BE(0)%100;
  return bucket<percentage;
}

// src/flags/eval.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {evaluateFlag} from './eval';

describe('evaluateFlag properties',()=>{
  it('is deterministic — repeated calls return same value',()=>{
    fc.assert(fc.property(fc.string({minLength:1}),fc.string({minLength:1}),fc.integer({min:0,max:100}),(uid,key,pct)=>{
      const a=evaluateFlag(uid,key,pct);
      const b=evaluateFlag(uid,key,pct);
      return a===b;
    }),{numRuns:500});
  });
  it('is monotonic in percentage — if true at N%, true at N+k%',()=>{
    fc.assert(fc.property(fc.string({minLength:1}),fc.string({minLength:1}),fc.integer({min:0,max:99}),fc.integer({min:1,max:50}),(uid,key,pct,delta)=>{
      const lower=evaluateFlag(uid,key,pct);
      const higher=evaluateFlag(uid,key,Math.min(100,pct+delta));
      return !lower||higher;
    }),{numRuns:500});
  });
  it('approximates target distribution',()=>{
    const PCT=30;
    let trues=0;
    const N=10000;
    for(let i=0;i<N;i++){
      if(evaluateFlag(`user-${i}`,'flag-A',PCT))trues++;
    }
    const observed=trues/N*100;
    expect(Math.abs(observed-PCT)).toBeLessThan(2); // ±2% tolerance at N=10k
  });
  it('0% never true, 100% always true',()=>{
    fc.assert(fc.property(fc.string({minLength:1}),fc.string({minLength:1}),(uid,key)=>{
      return evaluateFlag(uid,key,0)===false&&evaluateFlag(uid,key,100)===true;
    }),{numRuns:200});
  });
});

