import {DndContext,useSensor,useSensors,KeyboardSensor,PointerSensor,closestCenter,type DragEndEvent} from '@dnd-kit/core';
import {arrayMove,SortableContext,sortableKeyboardCoordinates,useSortable,verticalListSortingStrategy} from '@dnd-kit/sortable';
import {CSS} from '@dnd-kit/utilities';
import {useState} from 'react';

function Item({id}:{id:string}){
  const {attributes,listeners,setNodeRef,transform,transition}=useSortable({id});
  return (
    <li ref={setNodeRef} {...attributes} {...listeners} style={{transform:CSS.Transform.toString(transform),transition}}>
      {id}
    </li>
  );
}
export function SortableList({initial}:{initial:string[]}){
  const [items,setItems]=useState(initial);
  const sensors=useSensors(useSensor(PointerSensor),useSensor(KeyboardSensor,{coordinateGetter:sortableKeyboardCoordinates}));
  function handleDragEnd({active,over}:DragEndEvent){
    if(over&&active.id!==over.id){
      setItems((items)=>arrayMove(items,items.indexOf(active.id as string),items.indexOf(over.id as string)));
    }
  }
  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <SortableContext items={items} strategy={verticalListSortingStrategy}>
        <ul>{items.map(id=><Item key={id} id={id}/>)}</ul>
      </SortableContext>
    </DndContext>
  );
}

