import {describe,it,expect} from 'vitest';
import {render,screen} from '@testing-library/react';
import {userEvent} from '@testing-library/user-event';
import {SortableList} from './SortableList';

describe('SortableList keyboard',()=>{
  it('reorders via keyboard (Space+ArrowDown)',async()=>{
    const user=userEvent.setup();
    render(<SortableList initial={['A','B','C']}/>);
    const items=screen.getAllByRole('listitem');
    items[0].focus();
    await user.keyboard('{ }'); // pick up
    await user.keyboard('{ArrowDown}');
    await user.keyboard('{ }'); // drop
    const reordered=screen.getAllByRole('listitem').map(li=>li.textContent);
    expect(reordered).toEqual(['B','A','C']);
  });
  it('focus stays on the moved item (REGRESSION GUARD)',async()=>{
    const user=userEvent.setup();
    render(<SortableList initial={['A','B','C']}/>);
    const items=screen.getAllByRole('listitem');
    items[0].focus();
    await user.keyboard('{ }{ArrowDown}{ }');
    expect(document.activeElement?.textContent).toBe('A');
  });
});

